import{_ as a,o as n,c as e,ac as i}from"./chunks/framework.DnBnwVZk.js";const h=JSON.parse('{"title":"Nginx开机自动启动","description":"","frontmatter":{"date":"2019-07-14T00:00:00.000Z","categories":["Linux"],"tags":["nginx"],"publish":true},"headers":[],"relativePath":"views/linux/NginxAutoStart.md","filePath":"views/linux/NginxAutoStart.md","lastUpdated":1775803235000}'),t={name:"views/linux/NginxAutoStart.md"};function p(l,s,c,r,o,d){return n(),e("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1563062400000"},[...s[0]||(s[0]=[i(`<h1 id="nginx开机自动启动" tabindex="-1">Nginx开机自动启动 <a class="header-anchor" href="#nginx开机自动启动" aria-label="Permalink to &quot;Nginx开机自动启动&quot;">​</a></h1><p>切换到/lib/systemd/system/目录，创建nginx.service文件vim nginx.service</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /lib/systemd/system/</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">vim</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nginx.service</span></span></code></pre></div><p>文件内容如下：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[Unit]</span></span>
<span class="line"><span>Description=nginx</span></span>
<span class="line"><span>After=network.target</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[Service]</span></span>
<span class="line"><span>Type=forking</span></span>
<span class="line"><span>ExecStart=/usr/local/nginx/sbin/nginx</span></span>
<span class="line"><span>ExecReload=/usr/local/nginx/sbin/nginx reload</span></span>
<span class="line"><span>ExecStop=/usr/local/nginx/sbin/nginx quit</span></span>
<span class="line"><span>PrivateTmp=true</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[Install]</span></span>
<span class="line"><span>WantedBy=multi-user.target</span></span></code></pre></div><p>退出并保存文件，执行systemctl enable nginx.service使nginx开机启动</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> enable</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nginx.service</span></span></code></pre></div><hr><p>本文来自 stinkstone 的CSDN 博客 ，全文地址请点击：<a href="https://blog.csdn.net/stinkstone/article/details/78082748?utm_source=copy" target="_blank" rel="noreferrer">https://blog.csdn.net/stinkstone/article/details/78082748?utm_source=copy</a></p>`,9)])])}const u=a(t,[["render",p]]);export{h as __pageData,u as default};
